import React from 'react';
import {
  MemoryRouter as Router,
  Routes,
  Route,
  Navigate,
  useParams,
} from 'react-router-dom';

/** Legacy `/kt/nkc` → `/kt/pdc`, `/kt/but-toan-dieu-chinh` → `/kt/pkt` (menu/bookmark). */
const LegacyJournalEntryIdRedirect: React.FC<{ toPrefix: string }> = ({ toPrefix }) => {
  const { id } = useParams<{ id: string }>();
  return <Navigate to={id ? `${toPrefix}/${id}` : toPrefix} replace />;
};
import { Provider } from 'react-redux';
import { store } from './store/store';
import { AppLayout } from './components/layout/AppLayout';
import { SimpleNotFoundPage } from './components/layout/SimpleNotFoundPage';
import { isStandalone, showDevNav } from './dev/isStandalone';
import { StandaloneMockNav } from './standalone/StandaloneMockNav';
import { MemoryRouterSync } from './router/MemoryRouterSync';

// ── Kế Toán (kt) ──────────────────────────────────────────────────────────
const PhieuThuListPage      = React.lazy(() => import('./pages/kt/PhieuThuListPage'));
const PhieuThuFormPage      = React.lazy(() => import('./pages/kt/PhieuThuFormPage'));
const PhieuChiListPage      = React.lazy(() => import('./pages/kt/PhieuChiListPage'));
const PhieuChiFormPage      = React.lazy(() => import('./pages/kt/PhieuChiFormPage'));
const PhieuNhapMuaListPage  = React.lazy(() => import('./pages/kt/PhieuNhapMuaListPage'));
const PhieuNhapMuaFormPage  = React.lazy(() => import('./pages/kt/PhieuNhapMuaFormPage'));
const PhieuNhapMuaXTListPage = React.lazy(() => import('./pages/kt/PhieuNhapMuaXTListPage'));
const PhieuNhapMuaXTFormPage = React.lazy(() => import('./pages/kt/PhieuNhapMuaXTFormPage'));
const PhieuDieuChinhListPage   = React.lazy(() => import('./pages/kt/PhieuDieuChinhListPage'));
const PhieuDieuChinhFormPage   = React.lazy(() => import('./pages/kt/PhieuDieuChinhFormPage'));
const TamUngListPage        = React.lazy(() => import('./pages/kt/TamUngListPage'));
const TamUngFormPage        = React.lazy(() => import('./pages/kt/TamUngFormPage'));
const HoaDonMuaDvListPage   = React.lazy(() => import('./pages/kt/HoaDonMuaDvListPage'));
const HoaDonMuaDvFormPage   = React.lazy(() => import('./pages/kt/HoaDonMuaDvFormPage'));
const SoDuDauKyPage         = React.lazy(() => import('./pages/kt/SoDuDauKyPage'));
const DongSoPage            = React.lazy(() => import('./pages/kt/DongSoPage'));
const KyKeToanPage          = React.lazy(() => import('./pages/kt/KyKeToanPage'));
const ButToanDieuChinhPage      = React.lazy(() => import('./pages/kt/ButToanDieuChinhPage'));
const ButToanDieuChinhFormPage  = React.lazy(() => import('./pages/kt/ButToanDieuChinhFormPage'));
const PhanBoKyPage          = React.lazy(() => import('./pages/kt/PhanBoKyPage'));
const KetChuyenKyPage       = React.lazy(() => import('./pages/kt/KetChuyenKyPage'));
const PhanBoCcdcPage        = React.lazy(() => import('./pages/kt/PhanBoCcdcPage'));
const TinhGiaVonPage        = React.lazy(() => import('./pages/kt/TinhGiaVonPage'));
const ChuyenSoDuPage        = React.lazy(() => import('./pages/kt/ChuyenSoDuPage'));
const SoDuVatTuPage         = React.lazy(() => import('./pages/kt/SoDuVatTuPage'));
const SoDuHopDongPage       = React.lazy(() => import('./pages/kt/SoDuHopDongPage'));
const SoCaiPage             = React.lazy(() => import('./pages/kt/SoCaiPage'));
const SoQuyPage             = React.lazy(() => import('./pages/kt/SoQuyPage'));
const SoNhatKyThuTienPage   = React.lazy(() => import('./pages/kt/SoNhatKyThuTienPage'));
const SoNhatKyChiTienPage    = React.lazy(() => import('./pages/kt/SoNhatKyChiTienPage'));
const SoChiTietPage         = React.lazy(() => import('./pages/kt/SoChiTietPage'));
const SoTongHopPage         = React.lazy(() => import('./pages/kt/SoTongHopPage'));
const CongNoPage            = React.lazy(() => import('./pages/kt/CongNoPage'));
const CanDoiPhatSinhPage    = React.lazy(() => import('./pages/kt/CanDoiPhatSinhPage'));

// ── Giá Thành (gt) ──────────────────────────────────────────────────────────
const GiaThanhListPage   = React.lazy(() => import('./pages/gt/GiaThanhListPage'));
const GiaThanhDetailPage = React.lazy(() => import('./pages/gt/GiaThanhDetailPage'));

// ── Tài Sản Cố Định (tscd) ──────────────────────────────────────────────────
const TscdListPage        = React.lazy(() => import('./pages/tscd/TscdListPage'));
const TscdFormPage        = React.lazy(() => import('./pages/tscd/TscdFormPage'));
const TscdGiamPage        = React.lazy(() => import('./pages/tscd/TscdGiamPage'));
const TscdDieuChinhPage   = React.lazy(() => import('./pages/tscd/TscdDieuChinhPage'));
const TscdDieuChuyenPage  = React.lazy(() => import('./pages/tscd/TscdDieuChuyenPage'));
const TscdThoiKhauHaoPage = React.lazy(() => import('./pages/tscd/TscdThoiKhauHaoPage'));
const KhauHaoPage         = React.lazy(() => import('./pages/tscd/KhauHaoPage'));

const DevPage = React.lazy(() => import('./dev/DevPage'));
const DevSampleDataPage = React.lazy(() => import('./dev/DevSampleDataPage'));

const Suspense = ({ children }: { children: React.ReactNode }) => (
  <React.Suspense fallback={<div style={{ padding: '2rem' }}>Đang tải...</div>}>
    {children}
  </React.Suspense>
);

const AppShell: React.FC = () => (
  <>
    {isStandalone && <StandaloneMockNav />}
    <AppLayout />
  </>
);

const initialPath =
  typeof window !== 'undefined'
    ? window.location.pathname + window.location.search || '/'
    : '/';

const AppRouter: React.FC = () => (
  <>
    <MemoryRouterSync />
    <Routes>
        <Route path="/" element={isStandalone ? <AppShell /> : <AppLayout />}>
          {showDevNav && (
            <>
              <Route index element={<Navigate to="/dev" replace />} />
              <Route path="dev" element={<Suspense><DevPage /></Suspense>} />
              <Route path="dev/tao-du-lieu-mau" element={<Suspense><DevSampleDataPage /></Suspense>} />
              <Route path="kt/dev/tao-du-lieu-mau" element={<Suspense><DevSampleDataPage /></Suspense>} />
            </>
          )}

          {/* Kế Toán — MM appPaths */}
          <Route path="kt" element={<Navigate to="/kt/pt" replace />} />

          <Route path="kt/pt"           element={<Suspense><PhieuThuListPage /></Suspense>} />
          <Route path="kt/pt/them"      element={<Suspense><PhieuThuFormPage /></Suspense>} />
          <Route path="kt/pt/:id"       element={<Suspense><PhieuThuFormPage /></Suspense>} />
          <Route path="kt/phieu-thu"           element={<Suspense><PhieuThuListPage /></Suspense>} />
          <Route path="kt/phieu-thu/them"      element={<Suspense><PhieuThuFormPage /></Suspense>} />
          <Route path="kt/phieu-thu/:id"       element={<Suspense><PhieuThuFormPage /></Suspense>} />

          <Route path="kt/pc"           element={<Suspense><PhieuChiListPage /></Suspense>} />
          <Route path="kt/pc/them"      element={<Suspense><PhieuChiFormPage /></Suspense>} />
          <Route path="kt/pc/:id"       element={<Suspense><PhieuChiFormPage /></Suspense>} />
          <Route path="kt/phieu-chi"           element={<Suspense><PhieuChiListPage /></Suspense>} />
          <Route path="kt/phieu-chi/them"      element={<Suspense><PhieuChiFormPage /></Suspense>} />
          <Route path="kt/phieu-chi/:id"       element={<Suspense><PhieuChiFormPage /></Suspense>} />

          <Route path="kt/nkc"          element={<Navigate to="/kt/pdc" replace />} />
          <Route path="kt/nkc/them"     element={<Navigate to="/kt/pdc/them" replace />} />
          <Route path="kt/nkc/:id"      element={<LegacyJournalEntryIdRedirect toPrefix="/kt/pdc" />} />

          <Route path="kt/pdc"          element={<Suspense><PhieuDieuChinhListPage /></Suspense>} />
          <Route path="kt/pdc/them"     element={<Suspense><PhieuDieuChinhFormPage /></Suspense>} />
          <Route path="kt/pdc/:id"      element={<Suspense><PhieuDieuChinhFormPage /></Suspense>} />

          <Route path="kt/pnm"          element={<Suspense><PhieuNhapMuaListPage /></Suspense>} />
          <Route path="kt/pnm/them"     element={<Suspense><PhieuNhapMuaFormPage /></Suspense>} />
          <Route path="kt/pnm/:id"      element={<Suspense><PhieuNhapMuaFormPage /></Suspense>} />

          <Route path="kt/pnm-xt"       element={<Suspense><PhieuNhapMuaXTListPage /></Suspense>} />
          <Route path="kt/pnm-xt/them"  element={<Suspense><PhieuNhapMuaXTFormPage /></Suspense>} />
          <Route path="kt/pnm-xt/:id"   element={<Suspense><PhieuNhapMuaXTFormPage /></Suspense>} />

          <Route path="kt/hdmh-dv"      element={<Suspense><HoaDonMuaDvListPage /></Suspense>} />
          <Route path="kt/hdmh-dv/them" element={<Suspense><HoaDonMuaDvFormPage /></Suspense>} />
          <Route path="kt/hdmh-dv/:id"  element={<Suspense><HoaDonMuaDvFormPage /></Suspense>} />

          <Route path="kt/tam-ung"      element={<Suspense><TamUngListPage /></Suspense>} />
          <Route path="kt/tam-ung/them" element={<Suspense><TamUngFormPage /></Suspense>} />
          <Route path="kt/tam-ung/:id"  element={<Suspense><TamUngFormPage /></Suspense>} />

          <Route path="kt/so-du-dau-ky" element={<Suspense><SoDuDauKyPage /></Suspense>} />
          <Route path="kt/dong-so"      element={<Suspense><DongSoPage /></Suspense>} />
          <Route path="kt/ky"           element={<Suspense><KyKeToanPage /></Suspense>} />
          <Route path="kt/but-toan-dieu-chinh"      element={<Navigate to="/kt/pkt" replace />} />
          <Route path="kt/but-toan-dieu-chinh/them" element={<Navigate to="/kt/pkt/them" replace />} />
          <Route path="kt/but-toan-dieu-chinh/:id"  element={<LegacyJournalEntryIdRedirect toPrefix="/kt/pkt" />} />

          <Route path="kt/pkt"           element={<Suspense><ButToanDieuChinhPage /></Suspense>} />
          <Route path="kt/pkt/them"      element={<Suspense><ButToanDieuChinhFormPage /></Suspense>} />
          <Route path="kt/pkt/:id"       element={<Suspense><ButToanDieuChinhFormPage /></Suspense>} />

          <Route path="kt/phan-bo-cuoi-ky"  element={<Suspense><PhanBoKyPage /></Suspense>} />
          <Route path="kt/ket-chuyen-cuoi-ky" element={<Suspense><KetChuyenKyPage /></Suspense>} />
          <Route path="kt/phan-bo-ccdc"   element={<Suspense><PhanBoCcdcPage /></Suspense>} />
          <Route path="kt/tinh-gia-von"  element={<Suspense><TinhGiaVonPage /></Suspense>} />
          <Route path="kt/chuyen-so-du"  element={<Suspense><ChuyenSoDuPage /></Suspense>} />
          <Route path="kt/so-du-vat-tu"  element={<Suspense><SoDuVatTuPage /></Suspense>} />
          <Route path="kt/so-du-hop-dong" element={<Suspense><SoDuHopDongPage /></Suspense>} />

          <Route path="kt/so-cai"       element={<Suspense><SoCaiPage /></Suspense>} />
          <Route path="kt/so-quy"       element={<Suspense><SoQuyPage /></Suspense>} />
          <Route path="kt/so-nhat-ky-thu-tien" element={<Suspense><SoNhatKyThuTienPage /></Suspense>} />
          <Route path="kt/so-nhat-ky-chi-tien" element={<Suspense><SoNhatKyChiTienPage /></Suspense>} />
          <Route path="kt/so-chi-tiet"  element={<Suspense><SoChiTietPage /></Suspense>} />
          <Route path="kt/so-tong-hop"  element={<Suspense><SoTongHopPage /></Suspense>} />
          <Route path="kt/cong-no"      element={<Suspense><CongNoPage /></Suspense>} />
          <Route path="kt/cdps"         element={<Suspense><CanDoiPhatSinhPage /></Suspense>} />

          {/* Giá Thành */}
          <Route path="gt" element={<Navigate to="/gt/gia-thanh" replace />} />
          <Route path="gt/gia-thanh"     element={<Suspense><GiaThanhListPage /></Suspense>} />
          <Route path="gt/gia-thanh/:id" element={<Suspense><GiaThanhDetailPage /></Suspense>} />

          {/* Tài Sản Cố Định */}
          <Route path="tscd" element={<Navigate to="/tscd/danh-sach" replace />} />
          <Route path="tscd/danh-sach"     element={<Suspense><TscdListPage /></Suspense>} />
          <Route path="tscd/them"          element={<Suspense><TscdFormPage /></Suspense>} />
          <Route path="tscd/giam"          element={<Suspense><TscdGiamPage /></Suspense>} />
          <Route path="tscd/dieu-chinh"    element={<Suspense><TscdDieuChinhPage /></Suspense>} />
          <Route path="tscd/dieu-chuyen"   element={<Suspense><TscdDieuChuyenPage /></Suspense>} />
          <Route path="tscd/thoi-khau-hao" element={<Suspense><TscdThoiKhauHaoPage /></Suspense>} />
          <Route path="tscd/khau-hao"     element={<Suspense><KhauHaoPage /></Suspense>} />
          <Route path="tscd/:id"           element={<Suspense><TscdFormPage /></Suspense>} />

          <Route path="*" element={<SimpleNotFoundPage />} />
      </Route>
    </Routes>
  </>
);

const Root: React.FC = () => (
  <Provider store={store}>
    <Router initialEntries={[initialPath]} initialIndex={0}>
      <AppRouter />
    </Router>
  </Provider>
);

export default Root;
